    // Función estática para obtener la instancia del singleton
    static int& get() {
        return value_;
    }

private:
    // Constructor privado para evitar la creación de instancias del singleton
    Singleton() {}

    // Variable estática para almacenar el valor del singleton
    static int value_;
};

